import re
import sys

def format_array(name, data_str):
    values = re.findall(r'0x[0-9a-fA-F]+', data_str)
    lines = []
    for i in range(0, len(values), 16):
        lines.append('    ' + ', '.join(values[i:i+16]))
    
    return f"static const unsigned char PROGMEM {name}[] = {{\n" + ',\n'.join(lines) + "\n};\n"

